INSERT INTO `blog_posts` (`id`, `title`, `slug`, `excerpt`, `content`, `cover_image`, `author_id`, `created_at`, `updated_at`) VALUES
(1, 'Welcome to The Rebirth of a Queen: Where Healing Meets Power', 'welcome-to-the-rebirth-of-a-queen-where-healing-meets-power', 'Imagine a world where women and girls walk freely, safely, and without the shadow of fear. At The Rebirth of a Queen, this isn\'t just a dream—it is the mission driving everything we do.', '<h3 data-path-to-node=\"2\"><b>Our Vision: A World Free of Violence</b></h3><h3 data-path-to-node=\"2\"><b><br></b></h3><p data-path-to-node=\"3\">Imagine a world where women and girls walk freely, safely, and without the shadow of fear. At <b data-path-to-node=\"3\" data-index-in-node=\"94\">The Rebirth of a Queen</b>, this isn\'t just a dream—it is the mission driving everything we do.</p><p data-path-to-node=\"3\"><br></p><p data-path-to-node=\"4\">We are building a community entirely free of sexual violence and human trafficking. We believe that safety is a fundamental human right, not a privilege, and we are working tirelessly to turn that belief into reality across East Africa.</p><p data-path-to-node=\"4\"><br></p><h3 data-path-to-node=\"6\"><b>Who We Are</b></h3><p data-path-to-node=\"7\">The Rebirth of a Queen is much more than an organization; it is a movement rooted in lived experience and deep community connection. We are proudly:</p><p data-path-to-node=\"7\"><br></p><ul data-path-to-node=\"8\"><li><p data-path-to-node=\"8,0,0\"><b data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Women-Led:</b> Guided by the strength, wisdom, and resilience of women who understand the unique challenges facing our communities.</p><p data-path-to-node=\"8,0,0\"><br></p></li><li><p data-path-to-node=\"8,1,0\"><b data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Survivor-Led:</b> Built on the unshakeable truth that healing and leadership begin with those who have walked the path and emerged victorious.</p><p data-path-to-node=\"8,1,0\"><br></p></li><li><p data-path-to-node=\"8,2,0\"><b data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Community-Led:</b> Working hand-in-hand with local leaders, families, and grassroots networks to create sustainable, culturally rooted change.</p><p data-path-to-node=\"8,2,0\"><br></p></li></ul><h3 data-path-to-node=\"10\"><b>What We Do</b></h3><p data-path-to-node=\"11\">Our work spans the entire spectrum of prevention, protection, and restoration. Across East Africa, we focus on:</p><p data-path-to-node=\"11\"><br></p><ul data-path-to-node=\"12\"><li><p data-path-to-node=\"12,0,0\"><b data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Prevention:</b> Educating communities, challenging harmful norms, and equipping vulnerable populations with the tools to spot and stop trafficking and violence before they occur.</p><p data-path-to-node=\"12,0,0\"><br></p></li><li><p data-path-to-node=\"12,1,0\"><b data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Empowerment &amp; Healing:</b> Providing safe spaces, holistic support, and resources for survivors to reclaim their narratives, heal from trauma, and rebuild their lives.</p><p data-path-to-node=\"12,1,0\"><br></p></li><li><p data-path-to-node=\"12,2,0\"><b data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Leadership &amp; Thriving:</b> Helping survivors transition from surviving to thriving by fostering leadership development, economic independence, and advocacy.</p><p data-path-to-node=\"12,2,0\"><br></p></li></ul><h3 data-path-to-node=\"14\"><b>Why \"The Rebirth of a Queen\"?</b></h3><p data-path-to-node=\"15\">Trauma and violence try to strip away a person\'s dignity, voice, and power. But they cannot destroy a queen\'s crown.</p><p data-path-to-node=\"16\">\"Rebirth\" represents the profound transformation that happens when survivors are given the support, community, and platform they deserve. It is about shedding the heavy armor of pain and stepping into a new dawn of agency, strength, and royalty. Every woman who walks through our doors is reclaiming her power—not just to exist, but to lead.</p><p data-path-to-node=\"16\"><img src=\"data:image/png;base64,\" style=\"width: 300px;\" data-filename=\"program_3.png\"><br></p><h3 data-path-to-node=\"18\"><b>Join Our Journey</b></h3><p data-path-to-node=\"19\">This website is your window into our work, our stories, and our community. Whether you are a survivor looking for a safe harbor, an ally wanting to stand with us, or someone eager to learn how to keep your community safe, <b data-path-to-node=\"19\" data-index-in-node=\"222\">you belong here</b>.</p><p data-path-to-node=\"19\"><br></p><ul data-path-to-node=\"20\"><li><p data-path-to-node=\"20,0,0\"><b data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Explore</b> our programs and resources.</p><p data-path-to-node=\"20,0,0\"><br></p></li><li><p data-path-to-node=\"20,1,0\"><b data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Read</b> stories of resilience and transformation.</p></li><li><p data-path-to-node=\"20,2,0\"><b data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Connect</b> with us to support the movement.</p></li></ul><p data-path-to-node=\"21\">Welcome to our new digital home. </p><p data-path-to-node=\"21\">Welcome to <b data-path-to-node=\"21\" data-index-in-node=\"44\">The Rebirth of a Queen</b>.</p>', '/uploads/1784742592719-rebirth_of_a_queen.png', 10, '2026-07-22 17:49:52', '2026-07-22 17:49:52');
INSERT INTO `blog_posts` (`id`, `title`, `slug`, `excerpt`, `content`, `cover_image`, `author_id`, `created_at`, `updated_at`) VALUES
